#!/bin/bash
# ==========================================================
# INSTALL ALL EDGE FUNCTIONS - Supabase Self-Hosted (Coolify)
# ==========================================================
# Instala TODAS as 14 Edge Functions + _shared no container
# Target: supabase.viniun.com.br
# Container: supabase-edge-functions
# Data: 12/02/2026
#
# COMO USAR:
# 1. Acesse Coolify > Automacao Yeslaser > supabase-viniun
# 2. Va em Terminal
# 3. Selecione container: supabase-edge-functions-*
# 4. Cole TODO o conteudo deste arquivo no terminal
# 5. Aguarde a verificacao final
# 6. Reinicie o container no Coolify
# ==========================================================

set -e

echo "========================================"
echo "  INSTALADOR - ALL EDGE FUNCTIONS"
echo "  14 functions + _shared modules"
echo "========================================"
echo ""

DEST_DIR="/home/deno/functions"

# Base64 do arquivo tar.gz com todas as functions
read -r -d '' FUNCTIONS_B64 << 'EOFBASE64' || true

EOFBASE64

# Criar diretorio temporario
TMP_DIR=$(mktemp -d)
echo "Diretorio temporario: $TMP_DIR"

# Decodificar e extrair
echo "Decodificando e extraindo functions..."
echo "$FUNCTIONS_B64" | base64 -d | tar -xzf - -C "$TMP_DIR"

# Listar extraidos
echo ""
echo "Arquivos extraidos:"
find "$TMP_DIR" -type f | sort
echo ""

# Instalar _shared
echo "Instalando _shared modules..."
mkdir -p "$DEST_DIR/_shared"
for file in secrets.ts unicodeSanitizer.ts; do
  if [ -f "$TMP_DIR/_shared/$file" ]; then
    cp "$TMP_DIR/_shared/$file" "$DEST_DIR/_shared/$file"
    echo "  OK: _shared/$file"
  else
    echo "  FALHA: _shared/$file nao encontrado"
  fi
done

# Instalar functions
echo ""
echo "Instalando 14 Edge Functions..."
FUNCTIONS=(
  "cliente-enviar-codigo"
  "cliente-verificar-codigo"
  "franqueado-servicos"
  "google-drive-sync"
  "meta-oauth-callback"
  "meta-send-message"
  "meta-sync"
  "meta-token-refresh"
  "meta-webhook"
  "social-media-proxy"
  "totem-checkin"
  "waha-proxy"
  "waha-webhook"
  "webhook-leads"
)

INSTALLED=0
for func in "${FUNCTIONS[@]}"; do
  if [ -f "$TMP_DIR/$func/index.ts" ]; then
    mkdir -p "$DEST_DIR/$func"
    cp "$TMP_DIR/$func/index.ts" "$DEST_DIR/$func/index.ts"
    SIZE=$(wc -c < "$DEST_DIR/$func/index.ts")
    echo "  OK: $func ($SIZE bytes)"
    INSTALLED=$((INSTALLED + 1))
  else
    echo "  FALHA: $func/index.ts nao encontrado"
  fi
done

# Limpar temporarios
rm -rf "$TMP_DIR"

# Verificacao final
echo ""
echo "========================================"
echo "  VERIFICACAO FINAL"
echo "========================================"
echo ""

VERIFIED=0
for func in "${FUNCTIONS[@]}"; do
  if [ -f "$DEST_DIR/$func/index.ts" ]; then
    SIZE=$(wc -c < "$DEST_DIR/$func/index.ts")
    echo "  OK: $func ($SIZE bytes)"
    VERIFIED=$((VERIFIED + 1))
  else
    echo "  FALHA: $func"
  fi
done

echo ""
echo "  _shared:"
for file in secrets.ts unicodeSanitizer.ts; do
  if [ -f "$DEST_DIR/_shared/$file" ]; then
    echo "    OK: $file"
  else
    echo "    FALHA: $file"
  fi
done

echo ""
echo "========================================"
echo "  RESULTADO: $VERIFIED/14 functions instaladas"
echo "========================================"
echo ""

if [ $VERIFIED -eq 14 ]; then
  echo "SUCESSO! Todas as functions foram instaladas."
  echo ""
  echo "PROXIMO PASSO:"
  echo "  Reinicie o container Edge Functions no Coolify"
  echo ""
else
  echo "ATENCAO: Algumas functions nao foram instaladas!"
  echo "Verifique os erros acima."
fi
